/**
 * BESPOKE LOGOS — full-color, merch-grade band logos (screen-print style:
 * 3-5 flat inks + the paper, bold keylines) authored as inner-SVG markup on a
 * 400 x h viewBox. Rendered by BandLogoLockup at the pure-DIY tier in place of
 * the composed type lockup; the xerox tier photocopies them to grayscale via
 * the existing [data-skin="diy-leaning"] CSS filter, and the hand-drawn /
 * script / print tiers behave exactly as before.
 *
 * Every logo is an ORIGINAL parody of its source act's merch language — never
 * a reproduction (same rule as names/marks). Internal SVG ids are namespaced
 * per band (e.g. bfg_*) so multiple logos can coexist in one document.
 *
 * Bands without an entry fall back to the composed lockup engine — the roster
 * is being upgraded in waves.
 */

export interface BespokeLogo {
  /** viewBox height (width is always 400). */
  h: number;
  /** Inner SVG markup (no <svg> wrapper), self-contained with its own colors. */
  svg: string;
}

